export const PERMISSION_DEFINITIONS = PERMISSION_GROUPS.flatMap((group) => group.permissions);
export const PERMISSION_KEYS = PERMISSION_DEFINITIONS.map((permission) => permission.key);
export const PERMISSION_KEY_SET = new Set(PERMISSION_KEYS);
export const PERMISSION_DEFINITION_BY_KEY = new Map(PERMISSION_DEFINITIONS.map((permission) => [permission.key, permission]));
export const CRITICAL_ADMIN_PERMISSIONS = [...PERMISSION_KEYS];
export const ADMIN_LIKE_ROLE_NAMES = [
    SUPER_ADMIN_ROLE_NAME,
    ADMIN_ROLE_NAME,
];
export const READ_ONLY_PERMISSION_KEYS = [
    ...PERMISSION_KEYS.filter((permission) => permission.endsWith(".read") ||
        permission.endsWith(".view") ||
        permission.endsWith(".ver")),
    "reports.export",
];
const withoutPermissions = (permissions, removedPermissions) => {
    const removedPermissionSet = new Set(removedPermissions);
    return permissions.filter((permission) => !removedPermissionSet.has(permission));
};
const uniquePermissions = (permissions) => {
    return Array.from(new Set(permissions)).sort((left, right) => left.localeCompare(right));
};
